    @Test
    public void testCollections_Deletecollection() throws Exception {

        var testHttpClient = Utils.createTestHTTPClient("deletecollection");
        Glean sdk = Glean.builder()
                .serverURL(Utils.environmentVariable("TEST_SERVER_URL", "http://localhost:18080"))
                .client(testHttpClient)
                .apiToken("<YOUR_BEARER_TOKEN_HERE>")
            .build();

        DeleteCollectionRequest req = DeleteCollectionRequest.builder()
                .ids(List.of(
                    930352L,
                    156719L,
                    25102L))
                .build();

        DeletecollectionResponse res = sdk.client().collections().delete()
                .request(req)
                .call();
        assertEquals(200, res.statusCode());
    }

